import { getRelativeLocaleUrl } from "astro:i18n";
import { stripBase, stripLocale } from "@/utils/withBase";
import { useTranslations } from "@/i18n";
import config from "@/config";

const locale = Astro.currentLocale ?? config.site.lang;
const t = useTranslations(locale);

// Strip base prefix and trailing slash, then locale prefix so segments
// reflect the logical page path only.
const pathWithoutBase = stripBase(Astro.url.pathname).replace(/\/+$/, "");
const currentUrlPath = stripLocale(pathWithoutBase, locale);

// Get url array from path
// eg: /tags/tailwindcss => ['tags', 'tailwindcss']
const breadcrumbList = currentUrlPath.split("/").slice(1).filter(Boolean);

const decodeSegment = (value: string) => {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
};

const navLabels: Record<string, string> = {
  posts: t.nav.posts,
  tags: t.nav.tags,
  about: t.nav.about,
  archives: t.nav.archives,
  search: t.nav.search,
};

// if breadcrumb is Home > Posts > [page] <etc>
// replace Posts with localized "Posts (page number)"
if (breadcrumbList[0] === "posts") {
  breadcrumbList.splice(
    0,
    2,
    `${t.nav.posts} (${t.pagination.page.toLowerCase()} ${breadcrumbList[1] || 1})`
  );
}

// if breadcrumb is Home > Tags > [tag] > [page] <etc>
// replace [tag] > [page] with localized [tag] (page number)
if (breadcrumbList[0] === "tags" && !isNaN(Number(breadcrumbList[2]))) {
  breadcrumbList.splice(
    1,
    3,
    `${decodeSegment(breadcrumbList[1])} ${
      Number(breadcrumbList[2]) === 1
        ? ""
        : `(${t.pagination.page.toLowerCase()} ${breadcrumbList[2]})`
    }`
  );
}

import { cacheDir } from "astro:config/server";
import crypto from "node:crypto";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

// Update/bump version when changing markup in _ogMarkup.ts, or fonts/config in [...slug].png.ts
const CACHE_VERSION = "v1";

// Cache directory, defaults to node_modules/.astro/og-images
const CACHE_DIR = path.join(fileURLToPath(cacheDir), "og-images");

// Check cache directory exists, if not create dir
function checkCacheDirExists() {
	if (!fs.existsSync(CACHE_DIR)) {
		fs.mkdirSync(CACHE_DIR, { recursive: true });
	}
}

// Returns a cache key based on CACHE_VERSION, a post's title & pubDate
function getCacheKey(title: string, pubDate: Date): string {
	const content = `${CACHE_VERSION}-${title}-${pubDate.toISOString()}`;
	return crypto.createHash("sha256").update(content).digest("hex").slice(0, 16);
}

// Return an OG Image from cache if it exists
export function readCache(title: string, pubDate: Date): Buffer | null {
	checkCacheDirExists();

	const cacheKey = getCacheKey(title, pubDate);
	const cacheFilePath = path.join(CACHE_DIR, `${cacheKey}.png`);

	if (fs.existsSync(cacheFilePath)) {
		console.info(`Found cached OG image for: ${title}`);
		return fs.readFileSync(cacheFilePath);
	}

	return null;
}

// Save image to cache
export function writeToCache(title: string, pubDate: Date, data: Buffer): void {
	const cacheKey = getCacheKey(title, pubDate);
	fs.writeFileSync(path.join(CACHE_DIR, `${cacheKey}.png`), data);
}

